const items = $input.all();
const screenerResults = items[0]?.json || [];
const technicals = items.slice(1).map(i => i.json);
const rsiMap = new Map(technicals.map(t => [t.ticker, t]));

const candidates = (Array.isArray(screenerResults) ? screenerResults : [])
  .filter(s => {
    const rsi = rsiMap.get(s.symbol);
    return rsi && parseFloat(rsi.rsi_value) >= 40 && parseFloat(rsi.rsi_value) <= 75;
  })
  .map(s => ({
    json: {
      ticker: s.symbol,
      company_name: s.companyName,
      sector: s.sector,
      market_cap: s.marketCap,
      price: s.price,
      volume: s.volume,
      beta: s.beta,
      rsi: rsiMap.get(s.symbol)?.rsi_value,
      strategy: 'short_term'
    }
  }))
  .slice(0, 30);

return candidates.length > 0 ? candidates : [{json: {skip: true}}];
